import{_ as t,o as a,c as i,a2 as r}from"./chunks/framework.ufzXw1qY.js";const p=JSON.parse('{"title":"Ultimate MCP Integration Doctrine","description":"Mandatory patterns for connecting, validating, routing, and safeguarding MCP tools in the OpenSIN ecosystem.","frontmatter":{"title":"Ultimate MCP Integration Doctrine","description":"Mandatory patterns for connecting, validating, routing, and safeguarding MCP tools in the OpenSIN ecosystem."},"headers":[],"relativePath":"best-practices/mcp-integration.md","filePath":"best-practices/mcp-integration.md"}'),n={name:"best-practices/mcp-integration.md"};function o(l,e,s,c,h,d){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="ultimate-mcp-integration-doctrine" tabindex="-1">Ultimate MCP Integration Doctrine <a class="header-anchor" href="#ultimate-mcp-integration-doctrine" aria-label="Permalink to &quot;Ultimate MCP Integration Doctrine&quot;">​</a></h1><blockquote><p><strong>RULE:</strong> MCPs are force multipliers only when they are explicit, validated, and observable. A mysterious MCP is worse than no MCP.</p></blockquote><hr><h2 id="_1-what-mcp-integration-must-achieve" tabindex="-1">1. What MCP Integration Must Achieve <a class="header-anchor" href="#_1-what-mcp-integration-must-achieve" aria-label="Permalink to &quot;1. What MCP Integration Must Achieve&quot;">​</a></h2><p>An MCP integration must make these clear:</p><ul><li>what tools it exposes</li><li>how it authenticates</li><li>how it is started / reached</li><li>what project problems it solves</li><li>what failure modes it introduces</li></ul><hr><h2 id="_2-prefer-explicit-discovery" tabindex="-1">2. Prefer Explicit Discovery <a class="header-anchor" href="#_2-prefer-explicit-discovery" aria-label="Permalink to &quot;2. Prefer Explicit Discovery&quot;">​</a></h2><p>Always verify live tool availability rather than trusting stale documentation.</p><h3 id="why" tabindex="-1">Why <a class="header-anchor" href="#why" aria-label="Permalink to &quot;Why&quot;">​</a></h3><p>MCP servers drift. Installed tools change. Old docs lie.</p><hr><h2 id="_3-startup-reachability" tabindex="-1">3. Startup &amp; Reachability <a class="header-anchor" href="#_3-startup-reachability" aria-label="Permalink to &quot;3. Startup &amp; Reachability&quot;">​</a></h2><p>For each MCP, document:</p><ul><li>startup mode (stdio / streamable HTTP / daemon)</li><li>host/port if relevant</li><li>health-check method</li><li>required env vars / credentials</li></ul><p>If you cannot prove reachability, you cannot rely on the MCP.</p><hr><h2 id="_4-security-requirements" tabindex="-1">4. Security Requirements <a class="header-anchor" href="#_4-security-requirements" aria-label="Permalink to &quot;4. Security Requirements&quot;">​</a></h2><p>MCP integrations must never silently inherit dangerous credentials or broad trust they do not need. Scope access tightly. Redact outputs where sensitive.</p><hr><h2 id="_5-tool-selection-discipline" tabindex="-1">5. Tool Selection Discipline <a class="header-anchor" href="#_5-tool-selection-discipline" aria-label="Permalink to &quot;5. Tool Selection Discipline&quot;">​</a></h2><p>Use an MCP only when it is the correct abstraction. Do not route simple local work through a remote MCP just to look sophisticated. Do not avoid an MCP when it is clearly the canonical path.</p><hr><h2 id="_6-failure-handling" tabindex="-1">6. Failure Handling <a class="header-anchor" href="#_6-failure-handling" aria-label="Permalink to &quot;6. Failure Handling&quot;">​</a></h2><p>When MCP calls fail, capture:</p><ul><li>tool name</li><li>target MCP</li><li>parameters shape</li><li>error class</li><li>whether retry is safe</li></ul><p>Do not hide MCP instability behind vague “tool failed” messages.</p><hr><h2 id="_7-final-rule" tabindex="-1">7. Final Rule <a class="header-anchor" href="#_7-final-rule" aria-label="Permalink to &quot;7. Final Rule&quot;">​</a></h2><p><strong>An MCP must reduce uncertainty, not increase it.</strong> If it adds magical hidden behavior, document and constrain it before trusting it.</p><hr><p><em>Last updated:</em> 2026-04-10<br><em>Status:</em> <strong>ACTIVE &amp; MANDATORY</strong><br><em>Maintainer:</em> sin-zeus</p><hr><h2 id="relevante-mandate" tabindex="-1">Relevante Mandate <a class="header-anchor" href="#relevante-mandate" aria-label="Permalink to &quot;Relevante Mandate&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mandat</th><th>Priority</th><th>Regel</th></tr></thead><tbody><tr><td><strong>webauto-nodriver-mcp</strong></td><td>0.0</td><td>EINZIGES autorisiertes Browser-MCP</td></tr><tr><td><strong>LLM via opencode CLI</strong></td><td>-2.5</td><td><code>opencode run --format json</code></td></tr></tbody></table>',35)])])}const m=t(n,[["render",o]]);export{p as __pageData,m as default};
